import { useState } from 'react';
import Navbar from './components/Navbar';
import Body from './components/Body';
import Links from './components/Links';

import github_white from './images/git_white.png'
import github from './images/github-512-1.webp'
import { useEffect } from 'react';

function App() {
  const [status, setStatus] = useState(true);
  const [navColor, setnavColor] = useState('rgb(250,250,250)');
  const [bodyColor, setbodyColor] = useState('rgb(255,255,255)');
  const [letterColor, setletterColor] = useState('rgb(0,0,0)');
  const [gitColor, setgitColor] = useState(github);

  let identifier = (id) => {
    return document.getElementById(id).style;
  }

  useEffect(() => {
    swapColor();
  }, []);

  const swapColor = () => {
    console.log(status);
    if (status === true) {
      setnavColor('rgb(37, 38, 39)');
      setbodyColor('rgb(41,42,45)');
      setletterColor('rgb(169,169,178)');
      setgitColor(github_white);
    } else {
      setnavColor('rgb(250, 250, 250)');
      setbodyColor('rgb(255,255,255)');
      setletterColor('rgb(0,0,0)');
      setgitColor(github);
    }
    setStatus(!status);
    identifier('one').backgroundColor = navColor;
    identifier('two').backgroundColor = navColor;
    identifier('my').color = letterColor;
    identifier('resume').color = letterColor;
    identifier('icon').color = letterColor;
    identifier('one').color = letterColor;
    identifier('two').color = letterColor;
    identifier('bucs').color = letterColor;
    identifier('content').backgroundColor = bodyColor;
    identifier('p1').backgroundColor = bodyColor;
    identifier('p2').backgroundColor = bodyColor;
    identifier('p3').backgroundColor = bodyColor;
    identifier('p4').backgroundColor = bodyColor;
    identifier('p1').color = letterColor;
    identifier('p2').color = letterColor;
    identifier('p3').color = letterColor;
    identifier('p4').color = letterColor;
    identifier('trade').backgroundColor = bodyColor;
    identifier('html-body').backgroundColor = bodyColor;
    document.getElementById('github').src = gitColor;
  }

  return (
    <div className="App">
      <Navbar swapColor={swapColor} />
      <Body/>
      <Links/>
    </div>
  );
}

export default App;
